pub fn parse_pair(s: &str) -> Result<(i32, i32), std::num::ParseIntError> {
    let mut it = s.split(',');
    let a = it.next().unwrap_or("0").parse::<i32>()?;
    let b = it.next().unwrap_or("0").parse::<i32>()?;
    Ok((a, b))
